.darma-loader-darma-custom-303 {
  width: fit-content;
  font-size: 34px;
  font-family: monospace;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #0284c7);
  --g:linear-gradient(90deg,var(--loader-color, #0284c7),var(--loader-secondary-color, #7dd3fc)) no-repeat text;
  background:var(--g) 0,var(--g) 1ch,var(--g) 2ch,var(--g) 3ch,var(--g) 4ch,var(--g) 5ch,var(--g) 6ch;
  background-position-y: 100%,0;
  animation: darma-loader-darma-custom-303-l16 2s linear infinite alternate;
}
